+import type { AnyColumn } from '~/column.ts';
+import { sql, type SQL, type SQLWrapper } from '../sql.ts';
+
+type ValueOf<T extends SQLWrapper> = T extends AnyColumn ? T['_']['data'] : T extends SQL<infer TValue> ? TValue : unknown;
+type OrderBy = SQLWrapper | SQL.Aliased;
+
+export type WindowBoundary = { readonly sql: SQL; readonly order: number };
+export type WindowFrame = SQL;
+
+export const unboundedPreceding: WindowBoundary = { sql: sql.raw('unbounded preceding'), order: Number.NEGATIVE_INFINITY };
+export const currentRow: WindowBoundary = { sql: sql.raw('current row'), order: 0 };
+export const unboundedFollowing: WindowBoundary = { sql: sql.raw('unbounded following'), order: Number.POSITIVE_INFINITY };
+
+function positionalBoundary(name: 'preceding' | 'following', value: number): WindowBoundary {
+	if (!Number.isInteger(value) || value < 0) {
+		throw new Error(`${name}() requires a non-negative integer, received ${value}`);
+	}
+	return { sql: sql.raw(`${value} ${name}`), order: name === 'preceding' ? -value : value };
+}
+
+export function preceding(value: number): WindowBoundary {
+	return positionalBoundary('preceding', value);
+}
+
+export function following(value: number): WindowBoundary {
+	return positionalBoundary('following', value);
+}
+
+function frame(kind: 'rows' | 'range', spec: { from: WindowBoundary; to?: WindowBoundary }): WindowFrame {
+	const to = spec.to ?? currentRow;
+	if (spec.from.order > to.order) {
+		throw new Error('Window frame from boundary must not be after to boundary');
+	}
+	return sql`${sql.raw(kind)} between ${spec.from.sql} and ${to.sql}`;
+}
+
+export function rows(spec: { from: WindowBoundary; to?: WindowBoundary }): WindowFrame {
+	return frame('rows', spec);
+}
+
+export function range(spec: { from: WindowBoundary; to?: WindowBoundary }): WindowFrame {
+	return frame('range', spec);
+}
+
+export interface WindowSpec {
+	partitionBy?: OrderBy | OrderBy[];
+	orderBy?: OrderBy | OrderBy[];
+	frame?: WindowFrame;
+}
+
+export class WindowFunction<T> implements SQLWrapper {
+	constructor(private readonly expression: SQL<T>) {}
+
+	over(spec?: WindowSpec | string): SQL<T> {
+		if (typeof spec === 'string') return sql`${this.expression} over ${sql.identifier(spec)}`;
+		const partitionBy = spec?.partitionBy ? (Array.isArray(spec.partitionBy) ? spec.partitionBy : [spec.partitionBy]) : [];
+		const orderBy = spec?.orderBy ? (Array.isArray(spec.orderBy) ? spec.orderBy : [spec.orderBy]) : [];
+		const parts: SQL[] = [];
+		if (partitionBy.length) parts.push(sql`partition by ${sql.join(partitionBy, sql`, `)}`);
+		if (orderBy.length) parts.push(sql`order by ${sql.join(orderBy, sql`, `)}`);
+		if (spec?.frame) parts.push(spec.frame);
+		return sql`${this.expression} over (${sql.join(parts, sql` `)})`;
+	}
+
+	getSQL(): SQL<T> { return this.expression; }
+}
+
+function window<T>(name: string, args: SQLWrapper[] = []): WindowFunction<T> {
+	return new WindowFunction(sql`${sql.raw(name)}(${sql.join(args, sql`, `)})`);
+}
+
+function positiveInteger(name: 'ntile' | 'nthValue', value: number): void {
+	if (!Number.isInteger(value) || value <= 0) throw new Error(`${name}() requires a positive integer, received ${value}`);
+}
+
+export const rowNumber = () => window<number>('row_number');
+export const rank = () => window<number>('rank');
+export const denseRank = () => window<number>('dense_rank');
+export const percentRank = () => window<number>('percent_rank');
+export const cumeDist = () => window<number>('cume_dist');
+export function ntile(buckets: number): WindowFunction<number> { positiveInteger('ntile', buckets); return window('ntile', [sql.raw(String(buckets))]); }
+
+export function lag<T extends SQLWrapper>(value: T): WindowFunction<ValueOf<T> | null>;
+export function lag<T extends SQLWrapper, TDefault extends SQLWrapper>(value: T, offset: number | undefined, defaultValue: TDefault): WindowFunction<Exclude<ValueOf<T>, null> | ValueOf<TDefault>>;
+export function lag<T extends SQLWrapper>(value: T, offset?: number, defaultValue?: SQLWrapper): WindowFunction<ValueOf<T> | null> { return window('lag', [value, ...(offset === undefined ? [] : [sql.raw(String(offset))]), ...(defaultValue === undefined ? [] : [defaultValue])]); }
+export function lead<T extends SQLWrapper>(value: T): WindowFunction<ValueOf<T> | null>;
+export function lead<T extends SQLWrapper, TDefault extends SQLWrapper>(value: T, offset: number | undefined, defaultValue: TDefault): WindowFunction<Exclude<ValueOf<T>, null> | ValueOf<TDefault>>;
+export function lead<T extends SQLWrapper>(value: T, offset?: number, defaultValue?: SQLWrapper): WindowFunction<ValueOf<T> | null> { return window('lead', [value, ...(offset === undefined ? [] : [sql.raw(String(offset))]), ...(defaultValue === undefined ? [] : [defaultValue])]); }
+export function firstValue<T extends SQLWrapper>(value: T): WindowFunction<ValueOf<T> | null> { return window('first_value', [value]); }
+export function lastValue<T extends SQLWrapper>(value: T): WindowFunction<ValueOf<T> | null> { return window('last_value', [value]); }
+export function nthValue<T extends SQLWrapper>(value: T, nth: number): WindowFunction<ValueOf<T> | null> { positiveInteger('nthValue', nth); return window('nth_value', [value, sql.raw(String(nth))]); }
+export function windowSum(value: SQLWrapper): WindowFunction<string | null> { return window('sum', [value]); }
+export function windowAvg(value: SQLWrapper): WindowFunction<string | null> { return window('avg', [value]); }
+export function windowMin<T extends SQLWrapper>(value: T): WindowFunction<ValueOf<T> | null> { return window('min', [value]); }
+export function windowMax<T extends SQLWrapper>(value: T): WindowFunction<ValueOf<T> | null> { return window('max', [value]); }
+export function windowCount(value?: SQLWrapper): WindowFunction<number> { return new WindowFunction(sql`count(${value ?? sql.raw('*')})`); }
